 {"id":"bd-1nac.1","title":"Command Pattern Infrastructure","description":"Implement reversible command trait for undoable operations.

## Requirements
- UndoableCmd trait with execute() and undo()
- Command metadata (description, timestamp)
- Merging capability for similar commands
- Memory-efficient command storage

## Proposed API

```rust
pub trait UndoableCmd: Send + Sync {
    /// Execute the command, returning the Cmd to run
    fn execute(&mut self) -> Cmd<M>;

    /// Undo the command, returning the Cmd to run
    fn undo(&mut self) -> Cmd<M>;

    /// Human-readable description for UI
    fn description(&self) -> &str;

    /// Check if this command can merge with another
    fn can_merge(&self, other: &dyn UndoableCmd) -> bool { false }

    /// Merge another command into this one
    fn merge(&mut self, other: Box<dyn UndoableCmd>) { }

    /// Size in bytes (for memory management)
    fn size_bytes(&self) -> usize;
}

pub struct CommandMetadata {
    pub description: String,
    pub timestamp: Instant,
    pub source: CommandSource,
}

#[derive(Clone, Copy)]
pub enum CommandSource {
    User,           // Direct user action
    Programmatic,   // Code-triggered
    Macro,          // Macro playback
}

// Example: TextInsertCmd
pub struct TextInsertCmd {
    pub target_id: WidgetId,
    pub position: usize,
    pub text: String,
    pub metadata: CommandMetadata,
}

impl UndoableCmd for TextInsertCmd {
    fn execute(&mut self) -> Cmd<M> {
        Cmd::batch(vec![
            Cmd::send(TextMsg::Insert(self.position, self.text.clone())),
        ])
    }

    fn undo(&mut self) -> Cmd<M> {
        Cmd::send(TextMsg::Delete(self.position, self.text.len()))
    }

    fn description(&self) -> &str { "Insert text" }

    fn can_merge(&self, other: &dyn UndoableCmd) -> bool {
        // Merge consecutive typing within 500ms
    }

    fn size_bytes(&self) -> usize {
        std::mem::size_of::<Self>() + self.text.len()
    }
}
```

