## Requirements
- Undo stack and redo stack
- Configurable max history depth
- Branch handling (clear redo on new action)
- Memory pressure handling

## Proposed API

```rust
/// History manager for undo/redo
pub struct HistoryManager {
    undo_stack: Vec<Box<dyn UndoableCmd>>,
    redo_stack: Vec<Box<dyn UndoableCmd>>,
    config: HistoryConfig,
    total_bytes: usize,
}

#[derive(Clone)]
pub struct HistoryConfig {
    pub max_depth: usize,         // Max commands to keep (default: 100)
    pub max_bytes: usize,         // Memory limit (default: 10MB)
    pub merge_timeout_ms: u64,    // Merge window for similar commands (default: 500)
}

impl HistoryManager {
    pub fn new(config: HistoryConfig) -> Self;

    // --- Core Operations ---

    /// Push command onto undo stack, clears redo stack
    pub fn push(&mut self, cmd: Box<dyn UndoableCmd>);

    /// Undo last command, returns Cmd to execute
    pub fn undo(&mut self) -> Option<Cmd<M>>;

    /// Redo last undone command, returns Cmd to execute
    pub fn redo(&mut self) -> Option<Cmd<M>>;

    /// Check if undo is available
    pub fn can_undo(&self) -> bool;

    /// Check if redo is available
    pub fn can_redo(&self) -> bool;

    // --- Info ---

    /// Get undo stack depth
    pub fn undo_depth(&self) -> usize;

    /// Get redo stack depth
    pub fn redo_depth(&self) -> usize;

    /// Get descriptions for UI display
    pub fn undo_descriptions(&self, limit: usize) -> Vec<&str>;
    pub fn redo_descriptions(&self, limit: usize) -> Vec<&str>;

    /// Memory usage
    pub fn memory_usage(&self) -> usize;

    // --- Maintenance ---

    /// Clear all history
    pub fn clear(&mut self);

    /// Trim to fit memory budget
    fn trim_to_budget(&mut self) {
        while self.total_bytes > self.config.max_bytes && !self.undo_stack.is_empty() {
            if let Some(cmd) = self.undo_stack.remove(0) {
                self.total_bytes -= cmd.size_bytes();
            }
        }
    }

    /// Try to merge with last command
    fn try_merge(&mut self, cmd: &mut Box<dyn UndoableCmd>) -> bool {
        if let Some(last) = self.undo_stack.last_mut() {
            if last.can_merge(cmd.as_ref()) {
                last.merge(std::mem::take(cmd));
                return true;
            }
        }
        false
    }
}

/// Branch handling: new action clears redo
impl HistoryManager {
    pub fn push(&mut self, cmd: Box<dyn UndoableCmd>) {
        // Clear redo stack on new action
        for cmd in self.redo_stack.drain(..) {
            self.total_bytes -= cmd.size_bytes();
        }

        // Try merge with previous
        if !self.try_merge(&mut cmd) {
            self.total_bytes += cmd.size_bytes();
            self.undo_stack.push(cmd);
        }

        // Enforce limits
        self.trim_to_budget();
        while self.undo_stack.len() > self.config.max_depth {
            if let Some(cmd) = self.undo_stack.remove(0) {
                self.total_bytes -= cmd.size_bytes();
            }
        }
    }
}
```

