## Proposed API

```rust
/// Stack of active modals
pub struct ModalStack {
    modals: Vec<ActiveModal>,
    next_z: u32,
}

struct ActiveModal {
    id: ModalId,
    z_index: u32,
    modal: Box<dyn Modal>,
    backdrop_opacity: f32,
    focus_trap_id: u32,
}

impl ModalStack {
    pub fn new() -> Self;

    // --- Stack Operations ---

    /// Push modal onto stack
    pub fn push(&mut self, modal: impl Modal + 'static) -> ModalId;

    /// Pop top modal, returns its result
    pub fn pop(&mut self) -> Option<ModalResult>;

    /// Pop specific modal by ID
    pub fn pop_id(&mut self, id: ModalId) -> Option<ModalResult>;

    /// Pop all modals
    pub fn pop_all(&mut self) -> Vec<ModalResult>;

    /// Get top modal (for input routing)
    pub fn top(&self) -> Option<&dyn Modal>;
    pub fn top_mut(&mut self) -> Option<&mut dyn Modal>;

    // --- State ---

    /// Check if any modals are open
    pub fn is_empty(&self) -> bool;

    /// Count of open modals
    pub fn depth(&self) -> usize;

    /// Get modal by ID
    pub fn get(&self, id: ModalId) -> Option<&dyn Modal>;

    // --- Rendering ---

    /// Render all modals in z-order
    pub fn render(&self, frame: &mut Frame, screen: Rect) {
        // Render backdrop for each modal
        for (i, modal) in self.modals.iter().enumerate() {
            let opacity = if i == self.modals.len() - 1 {
                modal.backdrop_opacity
            } else {
                modal.backdrop_opacity * 0.5  // Dim lower modals
            };
            self.render_backdrop(frame, screen, opacity);
            modal.modal.render(frame, self.modal_area(screen, &modal.modal));
        }
    }
}

/// Input routing: only top modal receives input
impl ModalStack {
    pub fn handle_event(&mut self, event: Event) -> Option<Cmd<M>> {
        if let Some(modal) = self.top_mut() {
            modal.handle_event(event)
        } else {
            None
        }
    }
}

/// Close on Escape (configurable)
impl ActiveModal {
    fn should_close_on_escape(&self) -> bool {
        self.modal.close_on_escape()
    }
}
```

